-- Realtime Algo Trading paper-mode foundation. Runtime creation is mirrored in backend/algo_store.py.
CREATE TABLE IF NOT EXISTS algo_sessions (session_id TEXT PRIMARY KEY, mode TEXT NOT NULL, status TEXT NOT NULL, capital REAL NOT NULL, available_funds REAL NOT NULL, max_trades INTEGER NOT NULL, max_loss REAL NOT NULL, risk_per_trade REAL NOT NULL, selected_trade_json TEXT, stop_reason TEXT, started_at TEXT, stopped_at TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS algo_orders (order_id TEXT PRIMARY KEY, session_id TEXT NOT NULL, symbol TEXT NOT NULL, side TEXT NOT NULL, quantity INTEGER NOT NULL, remaining_quantity INTEGER NOT NULL, entry_price REAL NOT NULL, current_price REAL NOT NULL, initial_stop_loss REAL NOT NULL, stop_loss REAL NOT NULL, trailing_stop_loss REAL NOT NULL, target REAL NOT NULL, status TEXT NOT NULL, pnl REAL NOT NULL DEFAULT 0, realized_pnl REAL NOT NULL DEFAULT 0, charges REAL NOT NULL DEFAULT 0, exit_reason TEXT, confidence REAL NOT NULL DEFAULT 0, strategy_reason TEXT, broker TEXT NOT NULL DEFAULT 'dummy', source TEXT NOT NULL DEFAULT 'yfinance', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, closed_at TEXT);
CREATE TABLE IF NOT EXISTS algo_positions (position_id TEXT PRIMARY KEY, order_id TEXT UNIQUE NOT NULL, session_id TEXT NOT NULL, symbol TEXT NOT NULL, side TEXT NOT NULL, quantity INTEGER NOT NULL, remaining_quantity INTEGER NOT NULL, average_price REAL NOT NULL, current_price REAL NOT NULL, unrealized_pnl REAL NOT NULL DEFAULT 0, realized_pnl REAL NOT NULL DEFAULT 0, status TEXT NOT NULL, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS algo_trades (trade_id TEXT PRIMARY KEY, order_id TEXT NOT NULL, session_id TEXT NOT NULL, symbol TEXT NOT NULL, side TEXT NOT NULL, quantity INTEGER NOT NULL, entry_price REAL NOT NULL, exit_price REAL NOT NULL, gross_pnl REAL NOT NULL, charges REAL NOT NULL, net_pnl REAL NOT NULL, exit_reason TEXT, confidence REAL NOT NULL DEFAULT 0, strategy_reason TEXT, improvement_json TEXT, opened_at TEXT, closed_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS algo_daily_performance (trade_date TEXT PRIMARY KEY, capital REAL NOT NULL DEFAULT 0, total_trades INTEGER NOT NULL DEFAULT 0, winning_trades INTEGER NOT NULL DEFAULT 0, losing_trades INTEGER NOT NULL DEFAULT 0, realized_pnl REAL NOT NULL DEFAULT 0, unrealized_pnl REAL NOT NULL DEFAULT 0, charges REAL NOT NULL DEFAULT 0, net_pnl REAL NOT NULL DEFAULT 0, snapshots_json TEXT, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS broker_accounts (account_id TEXT PRIMARY KEY, broker TEXT NOT NULL, mode TEXT NOT NULL, connected INTEGER NOT NULL DEFAULT 0, details_json TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS broker_api_logs (log_id TEXT PRIMARY KEY, broker TEXT NOT NULL, action TEXT NOT NULL, success INTEGER NOT NULL DEFAULT 0, request_json TEXT, response_json TEXT, error_message TEXT, created_at TEXT NOT NULL);
